#include<bits/stdc++.h>
using namespace std;
const long long mod=1e9+7;
long long fastpow(long long x,long long y)
{
    long long sum=1;
    while(y)
    {
        if(y%2==1)
        {
            sum=sum*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return sum;
}
long long dp[1000010];
long long jc[1000010],ny[1000010];
int C(int n,int m)
{
    return jc[n]*ny[m]%mod*ny[n-m]%mod;
}
int main()
{
    int t;
    scanf("%d",&t);
    jc[0]=ny[0]=1;
    for(int i=1;i<=1000000;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    ny[1000000]=fastpow(jc[1000000],mod-2);
    for(int i=999999;i>=1;i--)
    {
        ny[i]=ny[i+1]*(i+1)%mod;
    }
    dp[0]=dp[2]=1;
    for(int i=3;i<=1000000;i++)
    {
        dp[i]=(dp[i-1]+dp[i-2])*(i-1)%mod;
    }
    while(t--)
    {
        long long n,m;
        scanf("%lld%lld",&n,&m);
        printf("%lld\n",(C(n,m)*dp[n-m])%mod);
    }
    return 0;
}
